/* ─── 1. Injection de la photo ────────────── */
(function injectPhoto() {
    const b64 = '';
    const img = document.getElementById('cv-photo');
    if (img && b64.length > 100) {
        img.src = 'data:image/jpeg;base64,' + b64;
    }
})();

/* ─── 2. Animations d'apparition ─────────── */
(function initAnimations() {
    // On ajoute la classe fade-in aux éléments à animer
    const targets = document.querySelectorAll(
        '.entry, .section-main, .section-side, .name-block, .photo-wrap'
    );

    targets.forEach(function(el) {
        el.classList.add('fade-in');
    });

    // IntersectionObserver : déclenche l'animation au scroll
    if ('IntersectionObserver' in window) {
        const observer = new IntersectionObserver(function(entries) {
            entries.forEach(function(entry) {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.12 });

        targets.forEach(function(el) { observer.observe(el); });
    } else {
        // Fallback : tout rendre visible immédiatement
        targets.forEach(function(el) { el.classList.add('visible'); });
    }
})();

/* ─── 3. Délais en cascade ────────────────── */
(function staggerEntries() {
    document.querySelectorAll('.entry').forEach(function(el, i) {
        el.style.transitionDelay = (i * 0.07) + 's';
    });

    document.querySelectorAll('.section-side').forEach(function(el, i) {
        el.style.transitionDelay = (i * 0.1) + 's';
    });
})();
